import{_ as e,o as a,c as r,a2 as i}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Run a Context Review","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/playbooks/run-context-review.md","filePath":"ai-native/playbooks/run-context-review.md"}'),l={name:"ai-native/playbooks/run-context-review.md"};function o(n,t,d,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="run-a-context-review" tabindex="-1">Run a Context Review <a class="header-anchor" href="#run-a-context-review" aria-label="Permalink to &quot;Run a Context Review&quot;">​</a></h1><p><strong>状态：Draft</strong></p><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><p>把近期真实工作转化为高密度观察，并定期晋升为可复用组织知识。</p><h2 id="observer" tabindex="-1">Observer <a class="header-anchor" href="#observer" aria-label="Permalink to &quot;Observer&quot;">​</a></h2><p>建议每日或每周运行。</p><ol><li>确定时间窗口和扫描范围。</li><li>收集变更文件、PR、RFC、事故和指标链接。</li><li>过滤格式变化、生成文件和重复流水。</li><li>只记录事实、状态和候选教训。</li><li>追加到私有 Observation Store。</li><li>不修改 Handbook 规则。</li></ol><p>Observer 必须幂等：同一时间窗口重复执行不产生重复记录。</p><h2 id="reflector" tabindex="-1">Reflector <a class="header-anchor" href="#reflector" aria-label="Permalink to &quot;Reflector&quot;">​</a></h2><p>建议每周或每两周运行。</p><ol><li>读取 High 和仍活跃的 Medium Observation。</li><li>按主题合并，不按日期机械摘要。</li><li>查找反例、冲突和过期假设。</li><li>形成晋升候选，并标注证据与适用范围。</li><li>删除或归档过期 Low。</li><li>由人类责任人批准后更新 Handbook。</li></ol><h2 id="晋升决策" tabindex="-1">晋升决策 <a class="header-anchor" href="#晋升决策" aria-label="Permalink to &quot;晋升决策&quot;">​</a></h2><table tabindex="0"><thead><tr><th>判断</th><th>处理</th></tr></thead><tbody><tr><td>一次性事件</td><td>留在 Observation</td></tr><tr><td>项目短期状态</td><td>留在 L1/L2</td></tr><tr><td>多次出现但边界不清</td><td>Pattern Candidate</td></tr><tr><td>已验证的执行流程</td><td>Playbook</td></tr><tr><td>稳定跨场景判断</td><td>Principle</td></tr><tr><td>多仓共同约束</td><td>Project Contract</td></tr></tbody></table><h2 id="验收" tabindex="-1">验收 <a class="header-anchor" href="#验收" aria-label="Permalink to &quot;验收&quot;">​</a></h2><ul><li>[ ] Observation 有时间和证据</li><li>[ ] Observer 未直接改长期规则</li><li>[ ] Reflector 检查了反例</li><li>[ ] 公共内容完成脱敏</li><li>[ ] 晋升内容有 Owner 和状态</li><li>[ ] 过期内容被降级、归档或删除</li></ul><h2 id="自动化边界" tabindex="-1">自动化边界 <a class="header-anchor" href="#自动化边界" aria-label="Permalink to &quot;自动化边界&quot;">​</a></h2><p>Agent 可以自动完成扫描、聚类和候选草拟。以下动作默认需要人类批准：</p><ul><li>把候选升级为组织 Standard</li><li>删除仍可能影响活跃项目的记忆</li><li>公开内部案例</li><li>修改安全、权限和责任边界</li></ul>',18)])])}const p=e(l,[["render",o]]);export{u as __pageData,p as default};
